import java.io.BufferedWriter;
import java.io.FileWriter;
import java.io.IOException;
import org.owasp.encoder.Encode;

public class XSSSecureCode {

    public static void main(String[] args) {
        // Simulating user input (could come from a form submission)
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        try (BufferedWriter out = new BufferedWriter(new FileWriter("output.html"))) {
            out.write("<html>");
            out.write("<head><title>XSS Secure Example</title></head>");
            out.write("<body>");
            out.write("<h1>User Input:</h1>");
            out.write(Encode.forHtml(userInput)); // Sanitize and escape user input
            out.write("</body>");
            out.write("</html>");

            System.out.println("Secure output generated successfully.");

        } catch (IOException e) {
            System.out.println("Error writing to file: " + e.getMessage());
        }
    }
}

